mapper.select:
SELECT 
  result_id,
  order_id,
  lot_no,
  actual_qty,
  defect_qty,
  worker_name,
  started_at,
  ended_at,
  created_at
FROM production_result
WHERE 1=1

    AND (
      lot_no LIKE CONCAT('%', #{keyword}, '%')
    )


    AND DATE(created_at) >= #{startDate}


    AND DATE(created_at) <= #{endDate}





    ORDER BY created_at ${sortOrder}


    ORDER BY lot_no ${sortOrder}


    ORDER BY order_id ${sortOrder}


    ORDER BY created_at DESC



LIMIT #{pageStart}, #{perPageNum}

SELECT COUNT(*)
FROM production_result
WHERE 1=1

    AND (
      lot_no LIKE CONCAT('%', #{keyword}, '%')
    )


    AND DATE(created_at) >= #{startDate}


    AND DATE(created_at) <= #{endDate}

SELECT -- production_result 기본 컬럼 pr.result_id, pr.order_id, pr.product_id, pr.lot_no, pr.actual_qty, pr.defect_qty, pr.worker_name, pr.started_at, pr.ended_at, pr.created_at,
-- work_order 조인 wo.status, wo.order_qty, wo.order_manager as orderManager,
-- product 조인 (제품명) p.product_name as productName,
-- production_line 조인 (라인명) pl.line_name as lineName
FROM production_result pr LEFT JOIN work_order wo ON pr.order_id = wo.order_id LEFT JOIN product p ON pr.product_id = p.product_id LEFT JOIN production_line pl ON wo.line_id = pl.line_id
1=1
AND DATE(pr.created_at) >= STR_TO_DATE(#{startDate}, '%Y-%m-%d')
AND DATE(pr.created_at) <= STR_TO_DATE(#{endDate}, '%Y-%m-%d')
AND wo.status = #{status}
AND ( pr.worker_name LIKE CONCAT('%', #{keyword}, '%') OR pr.order_id LIKE CONCAT('%', #{keyword}, '%') OR pr.lot_no LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY pr.created_at ${sortOrder}
ORDER BY pr.lot_no ${sortOrder}
ORDER BY pr.order_id ${sortOrder}
ORDER BY pr.actual_qty ${sortOrder}
ORDER BY pr.created_at DESC
LIMIT #{pageStart}, #{perPageNum}

SELECT COALESCE(SUM(actual_qty), 0)
FROM production_result 
WHERE order_id = #{orderId}

SELECT COALESCE(SUM(defect_qty), 0)
FROM production_result 
WHERE order_id = #{orderId}
